[180] يُنظر: ((تفسير ابن جرير)) (14/515)، ((البسيط)) للواحدي (13/274)، ((تفسير الشوكاني)) (3/253). وممن قال مِن المفسرينَ: إنَّ قولَه تعالى: لِتَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ عائدٌ إلى آيةِ النهارِ المبصرةِ، أي: لتبتغوا في النهارِ: ابنُ جريرٍ، والسمرقندي، والواحدي، والسمعاني، والقرطبي، وابن جزي، وابنُ كثيرٍ، والشوكاني. يُنظر: ((تفسير ابن جرير)) (14/515)، ((تفسير السمرقندي)) (2/304)، ((البسيط)) للواحدي (13/274)، ((تفسير السمعاني)) (3/225)، ((تفسير القرطبي)) (10/228)، ((تفسير ابن جزي)) (1/443)، ((تفسير ابن كثير)) (5/49)، ((تفسير الشوكاني)) (3/253). قال الشوكاني: (ولم يذكُرْ هنا السُّكونَ في اللَّيلِ اكتفاءً بما قاله في موضعٍ آخرَ: هُوَ الَّذِي جَعَلَ لَكُمُ اللَّيْلَ لِتَسْكُنُوا فِيهِ وَالنَّهَارَ مُبْصِرًا
[يونس: 67]
). ((تفسير الشوكاني)) (3/253).

[193] يُنظر: ((تفسير ابن جرير)) (14/526)، ((تفسير ابن كثير)) (5/52)، ((تفسير ابن جزي)) (1/443)، ((نظم الدرر)) للبقاعي (11/388)، ((تفسير الشوكاني)) (3/254)، ((تفسير السعدي)) (ص: 455). قال ابنُ جزي: (وَمَا كُنَّا مُعَذِّبِينَ حَتَّى نَبْعَثَ رَسُولًا قيل: إنَّ هذا في حُكمِ الدُّنيا، أي: أنَّ اللهَ لا يُهلِكُ أمَّةً إلَّا بعد الإعذارِ إليهم بإرسالِ رَسولٍ إليهم. وقيل: هو عامٌّ في الدُّنيا والآخرةِ، وأنَّ اللهَ لا يُعَذِّبُ قَومًا في الآخرة إلَّا وقد أرسَلَ إليهم رسولًا فكَفَروا به وعَصَوه، ويدُلُّ على هذا قَولُه تعالى: كُلَّمَا أُلْقِيَ فِيهَا فَوْجٌ سَأَلَهُمْ خَزَنَتُهَا أَلَمْ يَأْتِكُمْ نَذِيرٌ * قَالُوا بَلَى
[الملك: 8- 9]
). ((تفسير ابن جزي)) (1/443). وقال الشوكاني: (الظاهِرُ أنَّه لا يُعَذِّبُهم لا في الدُّنيا ولا في الآخرةِ إلَّا بعد الإعذارِ إليهم بإرسالِ الرُّسُلِ). ((تفسير الشوكاني)) (3/254).

[413] يُنظر: ((تفسير ابن جرير)) (14/565-568)، ((تفسير أبي السعود)) (5/168)، ((تفسير الألوسي)) (8/61)، ((تفسير ابن عاشور)) (15/79). قال ابنُ تيميَّةَ: (والتَّبذيرُ قد يكونُ في القَدْرِ: بأن يُعطيَ هؤلاء المُستحقِّينَ فوقَ ما يَصلُحُ، بحيث يَصرِفُ الزَّائِدَ على كفايتِهم إليهم، ويَعدِلُ به عمَّن هو أحوَجُ إليه وأحَقُّ به منهم. وقد يكونُ في الأصلِ: بأن يُعطى المالُ في المنافِعِ المُحَرَّمةِ، كمَهرِ البَغيِّ، وحُلوانِ الكُهَّانِ، فهذا مِن الذُّنوبِ، وذاك من الإسرافِ؛ ولهذا قال المؤمِنونَ: رَبَّنَا اغْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِي أَمْرِنَا
[آل عمران: 147]
). ((العقود)) (ص: 18-19). وقال أبو السعود: (التبذيرُ تفريقٌ في غير موضِعِه، مأخوذٌ من تفريق حبَّاتٍ وإلقائِها كيفما كان من غير تعهُّدٍ لمواقِعِه، لا عن الإكثارِ في صَرفِه إليهم، وإلَّا لناسبه الإسرافُ الذي هو تجاوُزُ الحَدِّ في صرفِه). ((تفسير أبي السعود)) (5/168). وقال ابن عاشور: (التبذيرُ: تفريقُ المالِ في غير وجهِه، وهو مرادِفُ الإسرافِ، فإنفاقُه في الفسادِ تبذيرٌ، ولو كان المقدارُ قليلًا، وإنفاقُه في المباحِ إذا بلغ حَدَّ السَّرَفِ تبذيرٌ، وإنفاقُه في وجوه البِرِّ والصَّلاحِ ليس بتبذير. وقد قال بعضُهم لمن رآه ينفِقُ في وجوه الخير: لا خيرَ في السَّرَفِ، فأجابه المنفِقُ: لا سَرَفَ في الخيرِ). ((تفسير ابن عاشور)) (15/79). وقيل: التبذيرُ: الإنفاقُ في معصيةِ الله. يُنظر: ((تفسير الثعلبي)) (6/95)، ((تفسير البغوي)) (3/130)، ((تفسير الخازن)) (3/128). وقال القصاب: (كُلُّ ما حَرَّمَ اللهُ على العبادِ أكْلَه أو شُرْبَه أو فِعْلَه، فأنفَقَ فيه مُنْفِقٌ نفَقةً؛ سُمِّيَ مُبَذِّرًا، صائرًا بها مِن إخوانِ الشَّياطينِ، كَفورًا لِرَبِّه جلَّ وتعالى... والسرفُ وإن كان منهيًّا عنه فليس بتبذيرٍ. إنَّما التبذيرُ: ما يُستعانُ به على المعاصي وحدَها). ((النكت الدالة على البيان)) (2/123).

[962] يُنظر: ((تفسير ابن جرير)) (15/15)، ((تفسير القرطبي)) (10/300)، ((مجموع الفتاوى)) لابن تيمية (13/342)، ((تفسير السعدي)) (ص: 464)، ((أضواء البيان)) للشنقيطي (3/178). قال الشِّنقيطيُّ: (قال بعضُ أهلِ العِلمِ: قارَبوا ذلك في ظَنِّهم لا فيما في نَفسِ الأمرِ. وقيل: معنى ذلك أنَّه خطَرَ في قلبِه صلَّى اللهُ عليه وسلَّم أن يُوافِقَهم في بَعضِ ما أحَبُّوا؛ ليَجُرَّهم إلى الإسلامِ لشِدَّةِ حِرصِه على إسلامِهم. وبيَّنَ في موضعٍ آخَرَ أنَّهم طَلَبوا منه الإتيانَ بغيرِ ما أُوحيَ إليه، وأنَّه امتنَعَ أشَدَّ الامتناعِ، وقال لهم: إنَّه لا يُمكِنُه أن يأتيَ بشَيءٍ مِن تِلقاءِ نَفسِه، بل يَتَّبِعُ ما أوحى إليه رَبُّه، وذلك في قَولِه: قَالَ الَّذِينَ لَا يَرْجُونَ لِقَاءَنَا ائْتِ بِقُرْآنٍ غَيْرِ هَذَا أَوْ بَدِّلْهُ قُلْ مَا يَكُونُ لِي أَنْ أُبَدِّلَهُ مِنْ تِلْقَاءِ نَفْسِي إِنْ أَتَّبِعُ إِلَّا مَا يُوحَى إِلَيَّ إِنِّي أَخَافُ إِنْ عَصَيْتُ رَبِّي عَذَابَ يَوْمٍ عَظِيمٍ
[يونس: 15]
). ((أضواء البيان)) (3/178). ويُنظر: ((تفسير أبي حيان)) (7/89)، ((تفسير ابن عاشور)) (15/173).

[1185] يُنظر: ((تفسير ابن جرير)) (15/80)، ((تفسير القرطبي)) (10/330)، ((تفسير ابن كثير)) (5/120)، ((تفسير السعدي)) (ص: 467)، ((تفسير ابن عاشور)) (15/209)، ((أضواء البيان)) للشنقيطي (3/184). وقال ابن كثير: (وقولُه تعالى: أَوْ تُسْقِطَ السَّمَاءَ كَمَا زَعَمْتَ أي: أنَّك وعَدْتَنا أنَّ يومَ القيامةِ تَنْشَقُّ فيه السَّماءُ وتَهِي، وتَدَلَّى أطرافُها، فعَجِّلْ ذلك في الدُّنيا، وأسقطْها كِسَفًا: أي: قِطَعًا، كقولِهم: اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنَ السَّمَاءِ أَوِ ائْتِنَا بِعَذَابٍ أَلِيمٍ
[الأنفال: 32]
). ((تفسير ابن كثير)) (5/120). وقال الشنقيطي: (أو يسقط السماء عليهم كِسَفًا: أي: قطعًا كما زعَم، أي في قوله تعالى: إِنْ نَشَأْ نَخْسِفْ بِهِمُ الْأَرْضَ أَوْ نُسْقِطْ عَلَيْهِمْ كِسَفًا مِنَ السَّمَاء الآية
[سبأ: 9]
). ((أضواء البيان)) (3/184).

[1306] يُنظر: ((تفسير ابن جرير)) (15/105)، ((البسيط)) للواحدي (13/495)، ((تفسير ابن الجوزي)) (3/57)، ((تفسير ابن عطية)) (3/488)، ((تفسير الشوكاني)) (3/312). وممَّن قال بأنَّ المرادَ بالمسؤولينَ مِن اليهودِ المعاصرينَ لمحمَّدٍ صَلَّى اللهُ عليه وسلم: الذين أسلَموا منهم، كعبد اللهِ بنِ سَلامٍ رَضِيَ الله عنه: ابنُ الجوزي، وابنُ عطية، والشوكاني. يُنظر: ((تفسير ابن الجوزي)) (3/57)، ((تفسير ابن عطية)) (3/488)، ((تفسير الشوكاني)) (3/312). وذكر ابن عطية قولًا آخرَ في بيانِ المعنَى: (إِذْ جَاءَهُمْ يريدُ آباءَهم، وأدخَلهم في الضميرِ؛ إذ هم منهم. ويَحتَمِلُ أن يريدَ: فاسألْ بني إسرائيلَ الأوَّلينَ الذين جاءَهم موسى، وتكونُ إحالتُه إيَّاه على سُؤالِهم بطَلَبِ أخبارِهم، والنَّظَرِ في أحوالِهم وما في كُتُبِهم، نحوُ قَولِه تعالى: وَاسْأَلْ مَنْ أَرْسَلْنَا مِنْ قَبْلِكَ مِنْ رُسُلِنَا
[الزخرف: 45]
). ((تفسير ابن عطية)) (3/488، 489). وقال الرسعني: (المعنى: اسْأَلْهم عن الآياتِ؛ ليزدادوا طُمأنينةً ويقينًا، وليظهرَ لعامةِ اليهودِ بقولِ علمائِهم صدقُ ما أتيتَ به، فيكونَ حُجَّة عليهم. وقوله: إِذْ جَاءَهُمْ متعلقٌ بـ آتَيْنَا، أو بإضمارِ «اذكُر»، على معنى: «إذ جاءهم». وقيل: المعنى: ولقد آتينا موسى تسعَ آياتٍ بيِّناتٍ، فقُلْنا له: اسألْ بني إسرائيل، أي: سلْهم مِن فرعَون ليرسِلَهم معك، [واسْأَلْهم] عن إيمانِهم وحالِ دينِهم، وهل هم على ما كان عليه آباؤُهم الكرامُ مِن دين التوحيدِ، أو غيَّرهم الأمَّةُ الباغيةُ والدولةُ الطاغيةُ. أو يكون المعنى: سَلْ بني إسرائيل المعاضَدةَ والمناصَرةَ). ((تفسير الرسعني)) (4/227).
